/*
 * sw-push.js — custom Service Worker for pwaWaiter.
 *
 * Injected by vite-plugin-pwa in injectManifest mode:
 *   - self.__WB_MANIFEST holds the precache manifest generated by the plugin
 *   - We do NOT import workbox libraries here; the precache is left to the
 *     plugin's own injected code (the plugin wraps this file at build time).
 *
 * Our own responsibility: handle `push` events and notification clicks.
 */

// Required by injectManifest: workbox replaces `self.__WB_MANIFEST` with the precache array.
// Property assignment on `self` ensures the expression is NOT tree-shaken by Rollup.
self.precacheManifest = self.__WB_MANIFEST

// ---- Push handler --------------------------------------------------------

self.addEventListener('push', (event) => {
  let data = {}
  if (event.data) {
    try {
      data = event.data.json()
    } catch {
      // Backend should always send JSON, but fall back to plain text.
      data = { title: 'Buen Sabor', body: event.data.text() }
    }
  }

  const title = typeof data.title === 'string' ? data.title : 'Buen Sabor'
  const body = typeof data.body === 'string' ? data.body : ''

  const options = {
    body,
    icon: '/pwa-192.png',
    badge: '/pwa-192.png',
    data: data.data || {},
    // Vibrate pattern: short-short (100ms on, 50 off, 100 on). Silently ignored on unsupported platforms.
    vibrate: [100, 50, 100],
  }

  event.waitUntil(self.registration.showNotification(title, options))
})

// ---- Notification click handler -----------------------------------------

self.addEventListener('notificationclick', (event) => {
  event.notification.close()

  event.waitUntil(
    self.clients
      .matchAll({ type: 'window', includeUncontrolled: true })
      .then((clientList) => {
        // Focus an existing pwaWaiter window if already open
        for (const client of clientList) {
          if (client.url.includes(self.location.origin) && 'focus' in client) {
            return client.focus()
          }
        }
        // Otherwise open a new one at /tables
        if (self.clients.openWindow) {
          return self.clients.openWindow('/tables')
        }
        return null
      }),
  )
})

// ---- Lifecycle ------------------------------------------------------------

self.addEventListener('install', () => {
  // Activate immediately so updates take effect without waiting for old tabs to close.
  self.skipWaiting()
})

self.addEventListener('activate', (event) => {
  event.waitUntil(self.clients.claim())
})
